/* ── 상세 보기용 헬퍼: 목록에서 이전/다음 글을 구함 ── */
function board_neighbors($arr, $id) {
    $ids = array_keys($arr);
    $pos = array_search($id, $ids);
    return [
        'prev' => ($pos !== false && $pos > 0) ? $arr[$ids[$pos - 1]] : null,           // 위(최신 방향)
        'next' => ($pos !== false && $pos < count($ids) - 1) ? $arr[$ids[$pos + 1]] : null, // 아래(이전 방향)
    ];
}
